actions.action:
Expected naming pattern: {name}-v{version}.{ext} or {name}_v{version}.{ext}
Extract version number from filename (e.g., v1, v2, v3).
If no version in filename, default to version 1.

task.output_schema:

# asset-inventory.yaml

episode_id: "{episode_id}"
generated_at: "{ISO-8601 timestamp}"
assets_root: "episodes/{episode_id}/assets/"

summary:
  total_assets: {int}
  total_size_bytes: {int}
  total_size_human: "{e.g., 1.2 GB}"
  by_type:
    video: {count: {int}, size_bytes: {int}}
    narration: {count: {int}, size_bytes: {int}}
    frame: {count: {int}, size_bytes: {int}}
    sfx: {count: {int}, size_bytes: {int}}
    music: {count: {int}, size_bytes: {int}}
    subtitle: {count: {int}, size_bytes: {int}}
    metadata: {count: {int}, size_bytes: {int}}
    other: {count: {int}, size_bytes: {int}}
  by_status:
    generated: {int}
    approved: {int}
    flagged: {int}
    superseded: {int}
    missing: {int}

assets:
  - scene_id: "{scene_id}"
    asset_type: "{video|narration|frame|sfx|music|subtitle|metadata|other}"
    version: {int}
    is_latest: {boolean}
    file_path: "{relative path}"
    file_name: "{filename}"
    file_size_bytes: {int}
    file_size_human: "{e.g., 24.5 MB}"
    modified_at: "{ISO-8601}"
    status: "{generated|approved|flagged|superseded|missing}"

missing_assets:
  - scene_id: "{scene_id}"
    expected_type: "{asset_type}"
    expected_from: "{tool_name}"
    note: "Defined in scene-spec.yaml but no file found"
